// // This module implements a 2-to-1 multiplexer where the output Y is selected based on the value of the select line S. When S is 0, Y reflects the value of input B, and when S is 1, Y takes the value of input A.
module top_module(
    Y,
    A,
    B,
    S
);output Y;
    input A, B, S;

    wire notS;
    assign notS = ~S;

    assign Y = (A & notS) | (B & S);

endmodule
